+    #[test]
+    fn block_version_serde_round_trip() {
+        let v = BlockVersion {
+            block: BlockNumber(42),
+            commit_seq: CommitSeq(7),
+            writer: TxnId(3),
+            data: VersionData::Full(vec![0xBE; 16]),
